//Récupérer un élément avec la class loaderContainer !
const loaderContainer = document.querySelector(".loaderContainer");
//Faire disparaitre le loader une fois la page complètement chargée !
window.addEventListener("load", (e) => {
    //Ajouter la class fonduOut pour faire fondre le loader et son conteneur !
    loaderContainer.classList.add("fonduOut");
    //Attendre la fin du fondu du loader container avant de le supprimer du DOM !
    setTimeout((e) => {
        //Ajouter la class hidden pour cacher le conteneur du loader !
        loaderContainer.classList.add("hidden");
    }, 400);
});

